def detect_language():
    """Windows sistem dilini algıla"""
    try:
        if sys.platform == "win32":
            import ctypes
            lang_id = ctypes.windll.kernel32.GetUserDefaultUILanguage() & 0xFF
            mapping = {
                0x1F: "TR",  # Türkçe
                0x09: "EN",  # İngilizce
                0x07: "DE",  # Almanca
                0x19: "RU",  # Rusça
                0x04: "ZH",  # Çince
                0x0A: "ES",  # İspanyolca
                0x0C: "FR",  # Fransızca
                0x16: "PT",  # Portekizce
                0x01: "AR",  # Arapça
                0x11: "JA",  # Japonca
                0x12: "KO",  # Korece
                0x10: "IT",  # İtalyanca
            }
            return mapping.get(lang_id, "EN")
        return "EN"
    except:
        return "EN"

