import json as _json

_SETTINGS_FILE = os.path.join(os.path.expanduser("~"), ".spotifymp3_settings.json")

def load_settings():
    try:
        with open(_SETTINGS_FILE, encoding="utf-8") as f:
            return _json.load(f)
    except:
        return {}

def save_settings(data):
    try:
        s = load_settings()
        s.update(data)
        with open(_SETTINGS_FILE, "w", encoding="utf-8") as f:
            _json.dump(s, f)
    except:
        pass

# Dil: kayıtlı ayar > sistem dili
