# ── Spotify ───────────────────────────────────────────────────────────────────
WEB_HEADERS = {
    "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36",
    "Accept-Language": "tr-TR,tr;q=0.9",
}

def get_embed_session(ctype, pid):
    s = requests.Session()
    s.headers.update(WEB_HEADERS)
    r = s.get(f"https://open.spotify.com/embed/{ctype}/{pid}", timeout=15)
    r.raise_for_status()
    m = re.search(r'"accessToken"\s*:\s*"([^"]+)"', r.text)
    token = m.group(1) if m else None
    return token, s, r.text

def parse_embed_html(html):
    m = re.search(r'<script id="__NEXT_DATA__"[^>]*>(.*?)</script>', html, re.DOTALL)
    if not m: return None
    return json.loads(m.group(1))["props"]["pageProps"]["state"]["data"]["entity"]

def get_track_info_embed(tid, session):
    r = session.get(f"https://open.spotify.com/embed/track/{tid}",
                    headers=WEB_HEADERS, timeout=15)
    entity = parse_embed_html(r.text)
    if not entity: return None
    title  = entity.get("name","")
    artist = ", ".join(a["name"] for a in entity.get("artists",[]))
    covers = entity.get("coverArt",{}).get("sources",[])
    cover  = covers[-1]["url"] if covers else ""
    album  = entity.get("albumOfTrack",{}).get("name","") or ""
    return {"title":title.strip(),"artist":artist.strip(),"cover_url":cover,"album":album}

def get_all_playlist_ids(pid, token, session):
    r = session.get(
        f"https://spclient.wg.spotify.com/playlist/v2/playlist/{pid}",
        headers={"Authorization":f"Bearer {token}","Accept":"application/json",
                 "app-platform":"WebPlayer","Spotify-App-Version":"1.2.0"},
        timeout=20
    )
    r.raise_for_status()
    return [item["uri"].split(":")[-1]
            for item in r.json().get("contents",{}).get("items",[])
            if item.get("uri","").startswith("spotify:track:")]

def get_spotify_info(url, log_fn=None, update_log_fn=None):
    ctype = "playlist" if "/playlist/" in url else "album" if "/album/" in url else "track"
    pid   = url.rstrip("/").split("/")[-1].split("?")[0]
    token, session, html = get_embed_session(ctype, pid)
    entity = parse_embed_html(html)

    if ctype == "track":
        title  = entity.get("name","")
        artist = ", ".join(a["name"] for a in entity.get("artists",[]))
        covers = entity.get("coverArt",{}).get("sources",[])
        cover  = covers[-1]["url"] if covers else ""
        album  = entity.get("albumOfTrack",{}).get("name","") or ""
        return {"name":title,"type":"track",
                "tracks":[{"title":title,"artist":artist,"cover_url":cover,"album":album}]}

    if ctype == "album":
        name   = entity.get("name","album")
        covers = entity.get("coverArt",{}).get("sources",[])
        cover  = covers[-1]["url"] if covers else ""
        tracks = []
        for item in entity.get("trackList", entity.get("items",[])):
            try:
                title  = item.get("title") or item["track"]["name"]
                artist = item.get("subtitle","").replace("\xa0"," ") or \
                         ", ".join(a["name"] for a in item["track"]["artists"])
                if title: tracks.append({"title":title.strip(),"artist":artist.strip(),
                                         "cover_url":cover,"album":name})
            except: continue
        return {"name":name,"type":"album","tracks":tracks}

    # Playlist
    name = entity.get("name","playlist")
    embed_tracks = []
    for item in entity.get("trackList",[]):
        title  = item.get("title","")
        artist = item.get("subtitle","").replace("\xa0"," ").strip()
        if title:
            embed_tracks.append({"title":title.strip(),"artist":artist,
                                 "cover_url":"","album":""})

    all_ids = []
    if token:
        try:
            all_ids = get_all_playlist_ids(pid, token, session)
        except Exception as e:
            if log_fn: log_fn(f"  ID listesi alınamadı: {e}")

    total = max(len(all_ids), len(embed_tracks))

    if total <= len(embed_tracks):
        return {"name":name,"type":"playlist","tracks":embed_tracks}

    if log_fn: log_fn(f"  Toplam {total} şarkı, detaylar alınıyor...")

    remaining_ids = all_ids[len(embed_tracks):]
    tracks = embed_tracks[:]

    for i, tid in enumerate(remaining_ids):
        msg = T["fetching_tracks"].format(len(embed_tracks)+i+1, total)
        if update_log_fn:
            update_log_fn(msg)
        elif log_fn:
            log_fn(msg)
        try:
            tr = get_track_info_embed(tid, session)
            if tr: tracks.append(tr)
        except:
            tracks.append({"title":f"Track_{tid[:8]}","artist":"","cover_url":"","album":""})
        time.sleep(0.4)

    return {"name":name,"type":"playlist","tracks":tracks}

def safe_name(s):
    return re.sub(r'[\\/*?:"<>|]', "_", s).strip(". ")

# ── İnternet ─────────────────────────────────────────────────────────────────
def is_connected():
    try: requests.get("https://www.google.com", timeout=5); return True
    except: return False

def wait_for_connection(log_fn, stop_event, interval=15):
    attempt = 1
    while not stop_event.is_set():
        if is_connected():
            log_fn(T["reconnected"], "ok"); return True
        log_fn(T["retrying"].format(interval * attempt), "err")
        for _ in range(interval):
            if stop_event.is_set(): return False
            time.sleep(1)
        attempt += 1
    return False

# ── İndirme ───────────────────────────────────────────────────────────────────
CREATE_NO_WINDOW = 0x08000000 if sys.platform == "win32" else 0

def embed_cover(out_path, cover_url, ext):
    if not cover_url or ext not in ("mp3","m4a","aiff"): return
    try:
        import urllib.request, tempfile
        tmp_img = tempfile.mktemp(suffix=".jpg")
        urllib.request.urlretrieve(cover_url, tmp_img)
        tmp_out = out_path + ".covtmp"
        res = subprocess.run(
            [FFMPEG,"-y","-i",out_path,"-i",tmp_img,
             "-map","0:a","-map","1:v","-c:a","copy","-c:v","mjpeg",
             "-id3v2_version","3",
             "-metadata:s:v","title=Album cover",
             "-metadata:s:v","comment=Cover (front)",
             tmp_out],
            capture_output=True, timeout=30, creationflags=CREATE_NO_WINDOW
        )
        os.remove(tmp_img)
        if res.returncode == 0:
            os.replace(tmp_out, out_path)
        elif os.path.exists(tmp_out):
            os.remove(tmp_out)
    except: pass

def download_track(track, output_dir, quality, fmt, log_fn, stop_event):
    query    = f"{track['artist']} - {track['title']}"
    finfo    = FORMATS.get(fmt, FORMATS["MP3"])
    ext      = finfo["ext"]
    lossy    = finfo["lossy"]
    fname    = safe_name(query)
    out_path = os.path.join(output_dir, f"{fname}.{ext}")

    if os.path.exists(out_path):
        log_fn(T["already_exists"]); return True
    if stop_event.is_set(): return False

    tmp = os.path.join(output_dir, "_tmp_")
    os.makedirs(tmp, exist_ok=True)
    for f in glob.glob(os.path.join(tmp, "*")):
        try: os.remove(f)
        except: pass

    # yt-dlp — sadece ses indir
    opts = {
        "format": "bestaudio/best",
        "outtmpl": os.path.join(tmp, "%(id)s.%(ext)s"),
        "quiet": True,
        "no_warnings": True,
        "writethumbnail": False,
        "postprocessors": [],
        "noplaylist": True,
        "socket_timeout": 30,
        "retries": 3,
    }

    while not stop_event.is_set():
        try:
            with yt_dlp.YoutubeDL(opts) as ydl:
                # Önce YouTube Music'te ara, olmadı YouTube'da ara
                search_queries = [
                    f"ytsearch1:{query} audio",
                    f"ytsearch1:{query}",
                ]
                downloaded = False
                for sq in search_queries:
                    try:
                        ydl.download([sq])
                        downloaded = True
                        break
                    except Exception:
                        pass
                if not downloaded:
                    raise Exception("Hiçbir arama sonuç vermedi")
            break
        except Exception as e:
            err = str(e).lower()
            if any(k in err for k in ["network","connection","timeout","remote end",
                                       "errno","socket","ssl","unable to connect"]):
                log_fn(T["dl_err"].format("Bağlantı kesildi..."), "err")
                if not wait_for_connection(log_fn, stop_event): return False
                for f in glob.glob(os.path.join(tmp, "*")):
                    try: os.remove(f)
                    except: pass
            else:
                log_fn(T["dl_err"].format(str(e)[:80]), "err")
                return False

    if stop_event.is_set(): return False

    # İndirilen dosyayı bul — .mhtml ve .html REDDET
    files = [
        f for f in glob.glob(os.path.join(tmp, "*"))
        if os.path.isfile(f)
        and not f.endswith((".part", ".mhtml", ".html", ".ytdl"))
        and os.path.getsize(f) > 10_000  # en az 10 KB
    ]

    if not files:
        log_fn(T["no_audio"], "err")
        return False

    # En büyük dosyayı seç (gerçek ses dosyası)
    src = max(files, key=os.path.getsize)

    # ffmpeg ile dönüştür
    cmd = [FFMPEG, "-y", "-i", src, "-vn"]

    if fmt == "MP3":
        cmd += ["-acodec","libmp3lame","-ab",f"{quality}k","-ar","44100"]
    elif fmt == "M4A":
        cmd += ["-acodec","aac","-b:a",f"{quality}k"]
    elif fmt == "OGG":
        cmd += ["-acodec","libvorbis","-b:a",f"{quality}k"]
    elif fmt == "OPUS":
        cmd += ["-acodec","libopus","-b:a",f"{quality}k"]
    elif fmt == "AAC":
        cmd += ["-acodec","aac","-b:a",f"{quality}k"]
    elif fmt == "FLAC":
        cmd += ["-acodec","flac"]
    elif fmt == "WAV":
        cmd += ["-acodec","pcm_s16le","-ar","44100"]
    elif fmt == "AIFF":
        cmd += ["-acodec","pcm_s16be","-ar","44100"]
    elif fmt == "ALAC":
        cmd += ["-acodec","alac"]

    # Metadata
    if track.get("title"):  cmd += ["-metadata", f"title={track['title']}"]
    if track.get("artist"): cmd += ["-metadata", f"artist={track['artist']}"]
    if track.get("album"):  cmd += ["-metadata", f"album={track['album']}"]

    cmd.append(out_path)

    res = subprocess.run(cmd, capture_output=True, timeout=180, creationflags=CREATE_NO_WINDOW)

    try: os.remove(src)
    except: pass

    if res.returncode != 0:
        err_msg = res.stderr.decode("utf-8", errors="replace")[-300:]
        log_fn(f"  ffmpeg HATA: {err_msg}", "err")
        return False

    # Kapak resmi göm
    if track.get("cover_url"):
        embed_cover(out_path, track["cover_url"], ext)

    kb = os.path.getsize(out_path) // 1024
    log_fn(T["ok_msg"].format(fname, ext, kb), "ok")
    return True

