def add_right_click_menu(widget, root):
    menu = tk.Menu(root, tearoff=0, bg="#2a2a2a", fg="white",
                   activebackground="#1DB954", activeforeground="black",
                   relief="flat", bd=0)
    menu.add_command(label=T["ctx_paste"], command=lambda: widget.event_generate("<<Paste>>"))
    menu.add_command(label=T["ctx_copy"],  command=lambda: widget.event_generate("<<Copy>>"))
    menu.add_command(label=T["ctx_cut"],   command=lambda: widget.event_generate("<<Cut>>"))
    menu.add_separator()
    menu.add_command(label=T["ctx_clear"], command=lambda: widget.delete(0, tk.END))
    def show(event):
        try: menu.tk_popup(event.x_root, event.y_root)
        finally: menu.grab_release()
    widget.bind("<Button-3>", show)

