    def _on_format_change(self, event=None):
        fmt = self.fmt_var.get()
        labels = QUALITY_LABELS.get(fmt, QUALITY_LABELS["MP3"])
        self.q_combo.configure(values=labels)

        lossy = FORMATS[fmt]["lossy"]
        if lossy:
            self.q_combo.configure(state="readonly")
            self.q_combo.current(len(labels)-1)  # en yüksek kalite
            self.quality_label_widget.configure(text=T["quality_label"])
        else:
            self.q_combo.configure(state="readonly")
            self.q_combo.current(0)
            lbl = "WAV " + T["quality_label"] if fmt == "WAV" else f"{fmt} " + T["quality_label"]
            self.quality_label_widget.configure(text=lbl)

    def _get_quality_value(self):
        fmt = self.fmt_var.get()
        values = QUALITY_VALUES.get(fmt, QUALITY_VALUES["MP3"])
        labels = QUALITY_LABELS.get(fmt, QUALITY_LABELS["MP3"])
        try:
            idx = labels.index(self.quality_var.get())
            return values[idx]
        except:
            return values[-1]

    def _log(self, msg, tag="muted"):
        self.log.configure(state="normal")
        self.log.insert("end", msg+"\n", tag)
        self.log.see("end")
        self.log.configure(state="disabled")
        self._fetch_line = False

    def _log_update(self, msg):
        """Son satırı silerek güncelle — önceki loglar korunur"""
        self.log.configure(state="normal")
        if self._fetch_line:
            # Sadece en son satırı sil
            self.log.delete("end-1l linestart", "end-1c")
        self.log.insert("end", msg+"\n", "muted")
        self.log.see("end")
        self.log.configure(state="disabled")
        self._fetch_line = True

    def _change_lang(self, event=None):
        global LANG, T
        selected_name = self.lang_var.get()
        # İsimden kodu bul
        new_lang = next((k for k,v in LANGUAGES.items() if v == selected_name), LANG)
        if new_lang == LANG:
            return
        LANG = new_lang
        T    = STRINGS[LANG]
        save_settings({"lang": LANG})
        self._refresh_ui()

    def _refresh_ui(self):
        """Tüm UI metinlerini seçili dile göre güncelle"""
        self.title(T["title"])
        self.title_lbl.configure(text=f"  {T['title']}")
        self.fetch_btn.configure(text=T["fetch_btn"])
        self.pl_name.configure(text=T["placeholder"])
        self.pl_count.configure(text=T["placeholder2"])
        self.quality_label_widget.configure(text=T["quality_label"])
        self.dl_btn.configure(text=T["dl_btn"])
        self.stop_btn.configure(text=T["stop_btn"])
        # Dropdown'u güncelle
        self.lang_var.set(LANGUAGES[LANG])
        # Buton metinlerini güncelle
        self.dl_btn.configure(text=T["dl_btn"])
        self.stop_btn.configure(text=T["stop_btn"])
        self.open_btn_widget.configure(text=T["open_btn"])
        self.feedback_btn_widget.configure(text=T.get("feedback_btn","💌"))
        self.donate_btn_widget.configure(text=T.get("donate_btn","☕"))
        # Format label güncelle
        self._on_format_change()
        # Log mesajı
        self._log(T["lang_changed"], "inf")

