    def _open(self):
        d=self.dir_var.get()
        if os.path.isdir(d): os.startfile(d)
        else: messagebox.showinfo(T["info_title"],T["folder_empty"])

    def _fetch(self):
        url=self.url_var.get().strip()
        if not url:
            messagebox.showwarning(T["warn_title"],T["warn_no_url"]); return
        self.fetch_btn.configure(state="disabled",text=T["fetching"])
        self._log(T["fetching_info"],"inf")
        def go():
            try:
                info=get_spotify_info(
                    url,
                    log_fn=lambda m: self.after(0, lambda msg=m: self._log(msg,"muted")),
                    update_log_fn=lambda m: self.after(0, lambda msg=m: self._log_update(msg))
                )
                self._tracks=info["tracks"]
                base=self.dir_var.get()
                sn=safe_name(info["name"])
                if os.path.basename(base)==sn: base=os.path.dirname(base)
                self.dir_var.set(os.path.join(base,sn))
                self.after(0, lambda: self._fetch_ok(info))
            except Exception as e:
                self.after(0, lambda: self._fetch_err(str(e)))
        threading.Thread(target=go,daemon=True).start()

    def _fetch_ok(self,info):
        n=len(info["tracks"])
        ctype={"playlist":T["type_playlist"],"album":T["type_album"],
               "track":T["type_track"]}.get(info["type"],"")
        self.pl_name.configure(text=f"● {info['name']}  [{ctype}]")
        ct=T["found_single"] if n==1 and info["type"]=="track" else T["found_tracks"].format(n)
        self.pl_count.configure(text=ct)
        self._fetch_line = False
        self._log(f"'{info['name']}' [{ctype}] — {ct}","ok")
        self.fetch_btn.configure(state="normal",text=T["fetch_btn"])
        self.dl_btn.configure(state="normal")
        self.bar.configure(maximum=max(n,1),value=0)
        self.prog_lbl.configure(text=f"0 / {n}")

    def _fetch_err(self,e):
        self._fetch_line = False
        self._log(f"HATA: {e}","err")
        self.fetch_btn.configure(state="normal",text=T["fetch_btn"])
        messagebox.showerror(T["err_title"],T["err_fetch"].format(e))

    def _start(self):
        if not self._tracks:
            messagebox.showwarning(T["warn_title"],T["warn_no_tracks"]); return
        out=self.dir_var.get().strip()
        q=self._get_quality_value()
        fmt=self.fmt_var.get()
        self._stop.clear()
        self.dl_btn.configure(state="disabled")
        self.stop_btn.configure(state="normal")
        self.fetch_btn.configure(state="disabled")
        self.bar.configure(value=0)
        self._log(f"\n{T['dl_starting'].format(out)}","inf")
        def worker():
            os.makedirs(out,exist_ok=True)
            ok=0;fail=0;failed=[];total=len(self._tracks)
            for i,tr in enumerate(self._tracks,1):
                if self._stop.is_set():
                    self.after(0,lambda: self._log(T["stopped"],"err")); break
                lbl=f"{tr['artist']} - {tr['title']}"
                self.after(0,lambda l=lbl,i=i,t=total: self._log(f"[{i}/{t}] {l}","inf"))
                self.after(0,lambda i=i,t=total: self.prog_lbl.configure(text=f"{i} / {t}"))
                res=download_track(tr,out,q,fmt,
                    lambda m,tg="muted": self.after(0,lambda msg=m,tag=tg: self._log(msg,tag)),
                    self._stop)
                if res: ok+=1
                else:   fail+=1; failed.append(lbl)
                self.after(0,lambda v=i: self.bar.configure(value=v))
                time.sleep(1.5)
            tmp=os.path.join(out,"_tmp_")
            if os.path.isdir(tmp): shutil.rmtree(tmp,ignore_errors=True)
            fname=T.get("failed_file","failed_tracks.txt")
            if failed:
                with open(os.path.join(out,fname),"w",encoding="utf-8") as f:
                    f.write("\n".join(failed))
            self.after(0,lambda: self._done(ok,fail))
        threading.Thread(target=worker,daemon=True).start()

    def _stop_dl(self):
        self._stop.set(); self.stop_btn.configure(state="disabled")

    def _done(self,ok,fail):
        self._log(f"\n{T['dl_done'].format(ok,fail)}","ok")
        self.dl_btn.configure(state="normal")
        self.stop_btn.configure(state="disabled")
        self.fetch_btn.configure(state="normal")
        msg=T["done_msg"].format(ok)
        if fail: msg+=T["done_fail"].format(fail)
        messagebox.showinfo(T["done_title"],msg)

